var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우리 카페에서 웨딩 이벤트를 한다니!","JPN":"うちのカフェでウェディングイベントをするなんて！","ENG":"I can't believe we're hosting a wedding-themed event!","TWN":"我們咖啡廳裡居然要舉辦婚禮主題的活動！"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"진짜 결혼식처럼 화려했으면 좋겠어!","JPN":"本当の結婚式みたいに華やかだといいね！","ENG":"I want it to be extravagant, like a real wedding!","TWN":"希望能像真正的婚禮一樣奢華！"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"나 사실… 결혼식에 가본 적이 한 번도 없거든.","JPN":"私、実は……一度も結婚式に行ったことが無いの。","ENG":"I actually... have never been to a wedding before.","TWN":"其實……我還從來沒參加過婚禮。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"나도 많이는 못 가봤어. 전에 이웃집 마들렌 대장님 결혼식이 마지막이었거든.","JPN":"私もそれほど行ってないよ。前に近所のマドレーヌ隊長の結婚式に行ったのが最後。","ENG":"I haven't been to a lot of them either. Madeleine's wedding was the last one I went to.","TWN":"我也很少參加婚禮，最後一次是參加鄰居姊姊瑪德蓮的婚禮。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"아주 강한 상대였는데…… 어느 날 가버렸어.","JPN":"すごく強い人だったんだけど……ある日行っちゃったんだ。","ENG":"She was an admirable foe... but she just left one day.","TWN":"她是個很強的對手……不過後來就離開了。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어, 어딜?","JPN":"ど、どこに？","ENG":"L-left? Where to?","TWN":"是去哪？"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"결혼을 하고 난 어른들은 더 이상 동네 아이들과 놀아줄 시간이 없어지게 되거든.","JPN":"結婚すると時間がなくて、村の子どもたちとは遊んでくれなくなっちゃうからね。","ENG":"Married grown-ups don't have time to play with neighborhood children.","TWN":"結了婚的大人哪有時間和鄰居家的小鬼一起玩。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"놀이터에서 나무 막대기로 대련해 주던 게 생각나네…….","JPN":"遊び場で木の棒を使って相手してくれたことを思い出すなあ……","ENG":"I remember when she used to fight me with a wooden stick at the playground...","TWN":"我還記得我們在遊樂園裡，拿著木棍互毆的畫面呢……"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저런…….","JPN":"へえ……","ENG":"Oh...","TWN":"是喔……"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그래도 결혼식은 재밌었어! 꽃도 많고, 맛있는 음식도 많고. 분수대도 있었고!","JPN":"でも結婚式は面白かったよ！　花もたくさんあって、おいしいものもいっぱいで。噴水もあったし！","ENG":"Still, the wedding was fun! A lot of flowers, good food, and oh! There was a fountain too!","TWN":"不過婚禮很好玩！有很多花，很多好吃的，還有噴水池喔！"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"와아… 너무 낭만적이야. 분수대가 있는 곳에서 결혼이라니.","JPN":"わあ……ロマンチックだね。噴水のあるところで結婚式なんて。","ENG":"Wow... That's so romantic. Getting married at a venue with a fountain.","TWN":"哇……好浪漫喔，居然在有噴水池的地方結婚。"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"우리도 뒤뜰에 분수대 정도는 충분히 만들 수 있을걸?","JPN":"私たちも裏庭に噴水くらい余裕で作れるんじゃないかな？","ENG":"I'm sure we can afford to make a fountain in our backyard.","TWN":"我們也能在後院弄個噴水池吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗? 그런가?","JPN":"え？　そうなの？","ENG":"Oh, really?","TWN":"喔？是嗎？"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"마법으로 만들면 되지! 우린 카페니까 아예 초콜릿 분수대를 만드는 거야!","JPN":"魔法で作ればいいでしょ！　うちはカフェだから、いっそのことチョコレートの噴水を作るとか！","ENG":"We can make it with magic! Since we run a cafe, we can make a chocolate fountain!","TWN":"用魔法就好啦！我們是咖啡廳，那就乾脆弄個巧克力噴泉吧！"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그럼 마시멜로 꼬치를 잔뜩 만들어 줄까? 벽난로에 구워서 초콜릿 분수에 찍어 먹으면 더 맛있을 거야!","JPN":"じゃあ、マシュマロの串刺しをいっぱい作ろうか？　暖炉で焼いてチョコレートの噴水につけて食べればもっとおいしいよね！","ENG":"Should I make a bunch of marshmallows on sticks? It'll taste even better if you roast them by the fireplace and dip them in the chocolate fountain!","TWN":"那要烤棉花糖嗎？把棉花糖串起來後在壁爐裡烤一烤，再去沾巧克力噴泉一定很棒！"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"오케스트라를 초대해서 웅장한 연주도 해야 돼! 한 백 명쯤?","JPN":"オーケストラを招待して壮大な演奏も必要ね！　ざっと百人くらいかな？","ENG":"We should hire an orchestra for epic performances! An orchestra of... a hundred people, maybe?","TWN":"還要請樂隊來表演！像百人大樂隊那種？"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헉. 백 명이나?!","JPN":"えっ、百人も！？","ENG":"*Gasp* A hundred?!","TWN":"百，百人大樂隊？"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"하늘에도 엄청 큰 공을 여러 개 띄워서 빛이랑 꽃잎도 마구 뿌리고!","JPN":"空にもすっごく大きなボールを何個か浮かせて、光と花びらもいっぱい降らせて！","ENG":"Fly huge orbs in the sky so they shine and dispense flower petals!","TWN":"還要有超大氣球在天上飛，然後從空中撒落燈光和花瓣！"},"stage":{"bg":"TEHERANRO_DAYTIME","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};